import psycopg2
from prometheus_client import start_http_server, Gauge
import time

# Define Prometheus metrics
db_up = Gauge('db_up', 'Whether the db is up', ['username', 'password', 'host', 'connection'])

def check_database(username, password, host, connection):
    try:
        conn = psycopg2.connect(dbname="your_db", user=username, password=password, host=host)
        cur = conn.cursor()
        # Check if the database is up by running a simple query
        cur.execute('SELECT 1')
        db_up.labels(username=username, password=password, host=host, connection=connection).set(1)
    except psycopg2.Error:
        db_up.labels(username=username, password=password, host=host, connection=connection).set(0)
    finally:
        if conn is not None:
            conn.close()

def main():
    # Start Prometheus client
    start_http_server(8001)
    
    while True:
        check_database("your_username", "your_password", "localhost", "your_connection")
        time.sleep(60)  # Wait for 60 seconds before checking again

if __name__ == '__main__':
    main()